package api

import (
	"errors"
	"fmt"
	"math/rand"
	"runtime"
	"strings"
	"time"

	"github.com/dgraph-io/badger/v4"
)

// getMsToken 保存至 Douyin 中，每次登录都重新请求，然后每10分钟刷新一次
func (d *Douyin) getMsToken() (string, error) {
	if d.msToken.value != "" && time.Since(d.msToken.lastUpdated) < time.Hour {
		d.logger.Infof("msToken is valid, use cached value: %s", d.msToken.value)
		return d.msToken.value, nil
	}

	const (
		letters = "0123456789ABCDEFGHIJKLMNOPQRSTUVWXYZabcdefghijklmnopqrstuvwxyz"
		length  = 156 // 184
	)

	var b strings.Builder
	b.Grow(length)
	for i := 0; i < length; i++ {
		b.WriteByte(letters[rand.Intn(len(letters))])
	}

	resp, err := d.client.R().
		SetQueryParam("ms_appid", "6383").
		SetQueryParam("msToken", b.String()).
		SetHeaders(map[string]string{
			"User-Agent":               userAgent(),
			"Sec-Fetch-Site":           "cross-site",
			"Sec-Fetch-Storage-Access": "active",
			"Accept":                   "*/*",
			"Accept-Language":          "zh-CN,zh;q=0.9",
			"Content-Type":             "application/json; charset=UTF-8",
			"Origin":                   "https://www.douyin.com",
			"Referer":                  "https://www.douyin.com/",
			"Priority":                 "u=1, i",
			"Sec-CH-UA":                `"Google Chrome";v="147", "Not:A-Brand";v="24", "Chromium";v="147"`,
			"Sec-CH-UA-Mobile":         "?0",
			"Sec-CH-UA-Platform":       fmt.Sprintf(`"%s"`, runtime.GOOS),
			"Sec-Fetch-Dest":           "empty",
			"Sec-Fetch-Mode":           "cors",
		}).
		SetBodyJsonMarshal(map[string]any{
			"version":       1,
			"magic":         538969122,
			"dataType":      8,
			"url":           0,
			"tspFromClient": time.Now().UnixMilli(),
			"strData":       "",
		}).
		Post("https://mssdk.bytedance.com/web/common")
	if err != nil {
		return "", fmt.Errorf("request msToken api error: %w", err)
	}

	for _, resp := range resp.Cookies() {
		if strings.HasPrefix(resp.Name, "msToken") {
			d.msToken.value = resp.Value
			d.msToken.lastUpdated = time.Now()
			return d.msToken.value, nil
		}
	}
	if d.msToken.value == "" {
		return "", fmt.Errorf("get msToken error: %w", err)
	}

	return d.msToken.value, nil
}

func (d *Douyin) SetCookie(cookie string) error {
	cookie = strings.TrimSpace(cookie)
	if err := d.settings.SetKey(douyinCookieKey, cookie); err != nil {
		d.logger.Errorf("set cookie error: %s", err.Error())
		return errors.New("设置Cookie失败")
	}

	return nil
}

// GetCookie 获取Cookie
func (d *Douyin) GetCookie() (string, error) {
	cookie, err := d.settings.GetKey(douyinCookieKey)
	if err != nil {
		if errors.Is(err, badger.ErrKeyNotFound) {
			return "", errors.New("Cookie未设置，请先设置Cookie")
		}
		return "", errors.New("获取Cookie失败")
	}

	return cookie, nil
}
